    private void jPanel199MouseClicked(java.awt.event.MouseEvent evt) {//GEN-FIRST:event_jPanel199MouseClicked
        ClickAnimation(jPanel199);

        // TODO add your handling code here:
        
        if (comboBoxSuggestion1.getSelectedIndex()> 0){
        String selectedCountry = (String) comboBoxSuggestion1.getSelectedItem();
        callback.countryChanged(selectedCountry);
        dispose();}
        
        else{
            JOptionPane.showMessageDialog(null, "Please make sure you have chosen a country", "Error", JOptionPane.ERROR_MESSAGE);
        }
    }//GEN-LAST:event_jPanel199MouseClicked

    
